import './Banner.css';

function Banner({ movies }) {
  if (!movies || movies.length === 0) return null;

  const movie = movies[0];

  if (!movie) return null;

  return (
    <div
      className="banner" id='banner'
      style={{
        backgroundImage: `url(${movie.image || ""})`
      }}
    >
      <h1>{movie.title}</h1>
      <p>{movie.description}</p>
    </div>
  );
}

export default Banner;
